# Check for all imports and their usages
import re

files_to_check = {
    '/Users/zhouboli/Documents/maimai-assistant/src/modules/message.py': 'message.py',
    '/Users/zhouboli/Documents/maimai-assistant/src/modules/search.py': 'search.py',
    '/Users/zhouboli/Documents/maimai-assistant/src/cli/main.py': 'cli/main.py',
    '/Users/zhouboli/Documents/maimai-assistant/src/web/routers/pipeline.py': 'web/routers/pipeline.py',
}

unused_items = []

for filepath, name in files_to_check.items():
    with open(filepath, 'r') as f:
        content = f.read()

    # Extract imports from top of file
    import_section = content[:2000]  # Check first 2000 chars for imports

    # Check specific imports that might be unused
    checks = [
        ('Text', r'from rich\.text import Text', 'Text\('),
        ('questionary', r'import questionary', r'questionary\.[a-z_]+'),
    ]

    for item, import_pattern, usage_pattern in checks:
        if re.search(import_pattern, import_section):
            usage_count = len(re.findall(usage_pattern, content))
            if usage_count == 0:
                unused_items.append((name, item, "imported but never used"))
            elif usage_count == 1:
                # Check if it's just the import line
                line_with_import = re.search(rf'.*from.*import.*{item}.*', import_section)
                if line_with_import and len(re.findall(rf'\b{item}\b', content)) == 1:
                    unused_items.append((name, item, "imported but never used"))

# Also check TALENT_BANK constants
with open('/Users/zhouboli/Documents/maimai-assistant/src/modules/search.py', 'r') as f:
    content = f.read()

for const in ['TALENT_BANK_URL', 'TALENT_BANK_SEARCH_URL']:
    if re.search(rf'^{const}\s*=', content, re.MULTILINE):
        usage_count = len(re.findall(rf'\b{const}\b', content)) - 1  # -1 for definition
        if usage_count == 0:
            unused_items.append(('search.py', const, f"defined at line ~1209-1210 but never referenced"))

if unused_items:
    print("=== Potentially Unused Imports/Constants ===\n")
    for file, item, reason in unused_items:
        print(f"  {file}: {item}")
        print(f"    → {reason}\n")
else:
    print("No obvious unused imports found in basic check")
